1: // Package pong implements a simple terminal-based Pong game.
2: package pong
3: 
4: import (
5: 	"bufio"
6: 	"fmt"
7: 	"math/rand"
8: 	"os"
9: 	"os/exec"
10: 	"strings"
11: 	"time"
12: )
13: 
14: const (
15: 	width      = 60
16: 	height     = 20
17: 	paddleSize = 4
18: )
19: 
20: // Game holds the state of a Pong match.
21: type Game struct {
22: 	ballX, ballY   int
23: 	ballDX, ballDY int
24: 	leftY          int
25: 	rightY         int
26: 	leftScore      int
27: 	rightScore     int
28: 	paused         bool
29: 	quit           bool
30: 	tick           time.Duration
31: }
32: 
33: // New constructs a Game with the ball served toward a random player.
34: func New() *Game {
35: 	g := &Game{
36: 		ballDX:  1,
37: 		ballDY:  1,
38: 		leftY:   height/2 - paddleSize/2,
39: 		rightY:  height/2 - paddleSize/2,
40: 		tick:    80 * time.Millisecond,
41: 	}
42: 	if rand.Intn(2) == 0 {
43: 		g.ballDX = -1
44: 	}
45: 	return g
46: }
47: 
48: // ResetBall recenters the ball and serves it toward the player who conceded.
49: func (g *Game) ResetBall(towardLeft bool) {
50: 	g.ballX = width / 2
51: 	g.ballY = height / 2
52: 	g.ballDX = 1
53: 	g.ballDY = []int{-1, 1}[rand.Intn(2)]
54: 	if towardLeft {
55: 		g.ballDX = -1
56: 	}
57: }
58: 
59: // Step advances the simulation by one tick.
60: func (g *Game) Step() {
61: 	if g.paused || g.quit {
62: 		return
63: 	}
64: 
65: 	nextX := g.ballX + g.ballDX
66: 	nextY := g.ballY + g.ballDY
67: 
68: 	// Top/bottom wall bounce.
69: 	if nextY <= 0 || nextY >= height-1 {
70: 		g.ballDY = -g.ballDY
71: 		nextY = g.ballY + g.ballDY
72: 	}
73: 
74: 	// Left paddle collision.
75: 	if nextX == 1 && g.ballDX < 0 {
76: 		if nextY >= g.leftY && nextY < g.leftY+paddleSize {
77: 			g.ballDX = -g.ballDX
78: 			nextX = g.ballX + g.ballDX
79: 		}
80: 	}
81: 
82: 	// Right paddle collision.
83: 	if nextX == width-2 && g.ballDX > 0 {
84: 		if nextY >= g.rightY && nextY < g.rightY+paddleSize {
85: 			g.ballDX = -g.ballDX
86: 			nextX = g.ballX + g.ballDX
87: 		}
88: 	}
89: 
90: 	// Scoring.
91: 	if nextX <= 0 {
92: 		g.rightScore++
93: 		g.ResetBall(true)
94: 		return
95: 	}
96: 	if nextX >= width-1 {
97: 		g.leftScore++
98: 		g.ResetBall(false)
99: 		return
100: 	}
101: 
102: 	g.ballX = nextX
103: 	g.ballY = nextY
104: }
105: 
106: // MoveLeftPaddle clamps the paddle inside the playfield.
107: func (g *Game) MoveLeftPaddle(delta int) {
108: 	g.leftY = clamp(g.leftY+delta, 0, height-paddleSize)
109: }
110: 
111: // MoveRightPaddle clamps the paddle inside the playfield.
112: func (g *Game) MoveRightPaddle(delta int) {
113: 	g.rightY = clamp(g.rightY+delta, 0, height-paddleSize)
114: }
115: 
116: // TogglePause flips the paused flag.
117: func (g *Game) TogglePause() {
118: 	g.paused = !g.paused
119: }
120: 
121: // Quit ends the match.
122: func (g *Game) Quit() {
123: 	g.quit = true
124: }
125: 
126: // Over reports whether either player has reached the winning score.
127: func (g *Game) Over() bool {
128: 	return g.leftScore >= 5 || g.rightScore >= 5
129: }
130: 
131: // Winner returns the side that has reached the winning score, or "" if ongoing.
132: func (g *Game) Winner() string {
133: 	if g.leftScore >= 5 {
134: 		return "LEFT"
135: 	}
136: 	if g.rightScore >= 5 {
137: 		return "RIGHT"
138: 	}
139: 	return ""
140: }
141: 
142: // Render draws the current frame to a string.
143: func (g *Game) Render() string {
144: 	grid := make([][]rune, height)
145: 	for i := range grid {
146: 		grid[i] = make([]rune, width)
147: 		for j := range grid[i] {
148: 			grid[i][j] = ' '
149: 		}
150: 	}
151: 
152: 	// Top and bottom borders.
153: 	for x := 0; x < width; x++ {
154: 		grid[0][x] = '-'
155: 		grid[height-1][x] = '-'
156: 	}
157: 
158: 	// Net.
159: 	for y := 1; y < height-1; y++ {
160: 		if y%2 == 0 {
161: 			grid[y][width/2] = '|'
162: 		}
163: 	}
164: 
165: 	// Paddles.
166: 	for i := 0; i < paddleSize; i++ {
167: 		grid[g.leftY+i][0] = '#'
168: 		grid[g.rightY+i][width-1] = '#'
169: 	}
170: 
171: 	// Ball.
172: 	if g.ballY >= 0 && g.ballY < height && g.ballX >= 0 && g.ballX < width {
173: 		grid[g.ballY][g.ballX] = 'O'
174: 	}
175: 
176: 	var b strings.Builder
177: 	fmt.Fprintf(&b, "PONG  %2d : %-2d   (w/s=left, o/l=right, p=pause, q=quit)\n",
178: 		g.leftScore, g.rightScore)
179: 	for _, row := range grid {
180: 		b.WriteString(string(row))
181: 		b.WriteByte('\n')
182: 	}
183: 	return b.String()
184: }
185: 
186: func clamp(v, lo, hi int) int {
187: 	if v < lo {
188: 		return lo
189: 	}
190: 	if v > hi {
191: 		return hi
192: 	}
193: 	return v
194: }
195: 
196: // Run launches the interactive loop. It blocks until the player quits.
197: func (g *Game) Run(in *bufio.Reader) error {
198: 	if err := enableRawMode(); err != nil {
199: 		return err
200: 	}
201: 	defer disableRawMode()
202: 
203: 	if err := clearScreen(); err != nil {
204: 		return err
205: 	}
206: 
207: 	for !g.quit {
208: 		fmt.Print("\x1b[H")
209: 		fmt.Print(g.Render())
210: 		if g.Over() {
211: 			fmt.Printf("\n%s wins! Press q to exit.\n", g.Winner())
212: 		}
213: 
214: 		select {
215: 		case key := <-keyChan():
216: 			switch key {
217: 			case 'q', 'Q':
218: 				g.Quit()
219: 			case 'p', 'P':
220: 				g.TogglePause()
221: 			case 'w', 'W':
222: 				g.MoveLeftPaddle(-1)
223: 			case 's', 'S':
224: 				g.MoveLeftPaddle(1)
225: 			case 'o', 'O':
226: 				g.MoveRightPaddle(-1)
227: 			case 'l', 'L':
228: 				g.MoveRightPaddle(1)
229: 			}
230: 		case <-time.After(g.tick):
231: 		}
232: 
233: 		if g.Over() {
234: 			// Drain input until the player quits.
235: 			for {
236: 				select {
237: 				case key := <-keyChan():
238: 					if key == 'q' || key == 'Q' {
239: 						g.Quit()
240: 						return nil
241: 					}
242: 				case <-time.After(50 * time.Millisecond):
243: 				}
244: 			}
245: 		}
246: 
247: 		g.Step()
248: 	}
249: 	return nil
250: }
251: 
252: // keyChan returns a channel that yields one rune per keystroke.
253: // It is intentionally simple: a goroutine reads stdin in raw mode and
254: // forwards each rune. The channel is buffered so the game loop never blocks.
255: func keyChan() <-chan rune {
256: 	ch := make(chan rune, 4)
257: 	go func() {
258: 		defer close(ch)
259: 		buf := make([]byte, 1)
260: 		for {
261: 			n, err := os.Stdin.Read(buf)
262: 			if err != nil || n == 0 {
263: 				return
264: 			}
265: 			ch <- rune(buf[0])
266: 		}
267: 	}()
268: 	return ch
269: }
270: 
271: func enableRawMode() error {
272: 	// Best-effort: rely on the terminal already being in raw mode when piped
273: 	// via `stty raw -echo`. We still try to set it explicitly.
274: 	cmd := exec.Command("stty", "raw", "-echo")
275: 	cmd.Stdin = os.Stdin
276: 	return cmd.Run()
277: }
278: 
279: func disableRawMode() error {
280: 	cmd := exec.Command("stty", "sane")
281: 	cmd.Stdin = os.Stdin
282: 	return cmd.Run()
283: }
284: 
285: func clearScreen() error {
286: 	_, err := os.Stdout.WriteString("\x1b[2J")
287: 	return err
288: }
