8: func TestNewStartsCentered(t *testing.T) {
9: 	g := New()
10: 	if g.ballX != width/2 || g.ballY != height/2 {
11: 		t.Fatalf("ball not centered: got (%d,%d)", g.ballX, g.ballY)
12: 	}
13: 	if g.leftY != height/2-paddleSize/2 || g.rightY != height/2-paddleSize/2 {
14: 		t.Fatalf("paddles not centered: left=%d right=%d", g.leftY, g.rightY)
15: 	}
16: 	if g.leftScore != 0 || g.rightScore != 0 {
17: 		t.Fatalf("scores should start at 0")
18: 	}
19: }
20: 
21: func TestStepBouncesOffTopWall(t *testing.T) {
22: 	g := New()
23: 	g.ballX = 10
24: 	g.ballY = 1
25: 	g.ballDX = 1
26: 	g.ballDY = -1
27: 	g.Step()
28: 	if g.ballDY != 1 {
29: 		t.Fatalf("expected DY to flip to +1, got %d", g.ballDY)
30: 	}
31: 	if g.ballY != 2 {
32: 		t.Fatalf("expected ballY=2 after bounce, got %d", g.ballY)
33: 	}
34: }
