36: func TestStepBouncesOffLeftPaddle(t *testing.T) {
37: 	g := New()
38: 	g.ballX = 2
39: 	g.ballY = 5
40: 	g.ballDX = -1
41: 	g.ballDY = 1
42: 	g.leftY = 4
43: 	g.Step()
44: 	if g.ballDX != 1 {
45: 		t.Fatalf("expected DX to flip to +1, got %d", g.ballDX)
46: 	}
47: }
