49: func TestStepScoresRightWhenBallPassesLeft(t *testing.T) {
50: 	g := New()
51: 	g.ballX = 1
52: 	g.ballY = 5
53: 	g.ballDX = -1
54: 	g.ballDY = 0
55: 	g.Step()
56: 	if g.rightScore != 1 {
57: 		t.Fatalf("expected right score 1, got %d", g.rightScore)
58: 	}
59: 	if g.ballX != width/2 {
60: 		t.Fatalf("expected ball recentered, got %d", g.ballX)
61: 	}
62: }
