64: func TestStepScoresLeftWhenBallPassesRight(t *testing.T) {
65: 	g := New()
66: 	g.ballX = width - 2
67: 	g.ballY = 5
68: 	g.ballDX = 1
69: 	g.ballDY = 0
70: 	g.Step()
71: 	if g.leftScore != 1 {
72: 		t.Fatalf("expected left score 1, got %d", g.leftScore)
73: 	}
74: }
