76: func TestPaddleClamp(t *testing.T) {
77: 	g := New()
78: 	g.MoveLeftPaddle(-100)
79: 	if g.leftY != 0 {
80: 		t.Fatalf("expected leftY clamped to 0, got %d", g.leftY)
81: 	}
82: 	g.MoveLeftPaddle(1000)
83: 	if g.leftY != height-paddleSize {
84: 		t.Fatalf("expected leftY clamped to %d, got %d", height-paddleSize, g.leftY)
85: 	}
86: }
