88: func TestOverAndWinner(t *testing.T) {
89: 	g := New()
90: 	g.leftScore = 5
91: 	if !g.Over() {
92: 		t.Fatal("expected game over at 5")
93: 	}
94: 	if g.Winner() != "LEFT" {
95: 		t.Fatalf("expected LEFT winner, got %q", g.Winner())
96: 	}
97: 	g.leftScore = 0
98: 	g.rightScore = 5
99: 	if g.Winner() != "RIGHT" {
100: 		t.Fatalf("expected RIGHT winner, got %q", g.Winner())
101: 	}
102: }
