104: func TestRenderContainsScoreAndBall(t *testing.T) {
105: 	g := New()
106: 	g.ballX = 5
107: 	g.ballY = 5
108: 	out := g.Render()
109: 	if !strings.Contains(out, "PONG") {
110: 		t.Fatal("render missing header")
111: 	}
112: 	if !strings.Contains(out, "0 : 0") {
113: 		t.Fatal("render missing initial score")
114: 	}
115: 	if !strings.Contains(out, "O") {
116: 		t.Fatal("render missing ball")
117: 	}
118: 	if !strings.Contains(out, "#") {
119: 		t.Fatal("render missing paddles")
120: 	}
121: }
